function LxBuffHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.BuffListResp, self.OnBuffListResp, self)
    self:AddMsgHandler(LxProtoIds.BuffUpdateResp, self.OnBuffUpdateResp, self)
    self:AddMsgHandler(LxProtoIds.BuffRemoveResp, self.OnBuffRemoveResp, self)

    --增益来源列表
